"""
Full voice assistant: Porcupine wake word + faster-whisper STT
+ Anthropic Claude with tool use + pyttsx3 TTS.

  pip install pvporcupine pvrecorder faster-whisper anthropic pyttsx3
  export PICOVOICE_ACCESS_KEY="your_key_here"
  export ANTHROPIC_API_KEY="your_key_here"
"""

import os
import struct
import tempfile
import wave
from datetime import datetime
from typing import Any

import anthropic
import pvporcupine
import pyttsx3
from pvrecorder import PvRecorder
from faster_whisper import WhisperModel

# ── Configuration ──────────────────────────────────────────────────────────
PICOVOICE_KEY = os.environ["PICOVOICE_ACCESS_KEY"]
SAMPLE_RATE   = 16_000
VAD_THRESHOLD = 800     # RMS level above which audio is considered speech
SILENCE_FRAMES = 30     # ~0.5 s of consecutive silence ends an utterance
MAX_TURNS = 10          # maximum turns kept in context window

# ── Tool definitions ────────────────────────────────────────────────────────
TOOLS = [
    {
        "name": "get_current_time",
        "description": "Returns the current local time and date.",
        "input_schema": {"type": "object", "properties": {}, "required": []},
    },
    {
        "name": "get_weather",
        "description": "Returns a mock weather forecast for a city.",
        "input_schema": {
            "type": "object",
            "properties": {
                "location": {"type": "string", "description": "City name."}
            },
            "required": ["location"],
        },
    },
    {
        "name": "set_timer",
        "description": "Schedules a timer for the given number of minutes.",
        "input_schema": {
            "type": "object",
            "properties": {
                "minutes": {"type": "integer"}
            },
            "required": ["minutes"],
        },
    },
]


def run_tool(name: str, inputs: dict[str, Any]) -> str:
    if name == "get_current_time":
        return datetime.now().strftime("%I:%M %p on %A, %B %d")
    if name == "get_weather":
        loc = inputs.get("location", "your area")
        return f"Currently 72 °F and partly cloudy in {loc}."
    if name == "set_timer":
        m = inputs.get("minutes", 1)
        return f"Timer set for {m} minute{'s' if m != 1 else ''}."
    return "Unknown tool."


# ── Audio helpers ────────────────────────────────────────────────────────────
def _rms(frame: list[int]) -> float:
    return (sum(s * s for s in frame) / max(len(frame), 1)) ** 0.5


